package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

func main() {
	internalDomains := []string{
		"git.internal.company.com",
		"gitlab.company.local",
	}

	if len(internalDomains) > 0 {
		os.Setenv("GOPRIVATE", strings.Join(internalDomains, ","))
	}

	dependencies := []string{
		"github.com/gorilla/mux@latest",
		"golang.org/x/tools/cmd/goimports@latest",
	}

	for _, dep := range dependencies {
		fmt.Printf("Installing %s...\n", dep)
		cmd := exec.Command("go", "install", dep)
		cmd.Stdout = os.Stdout
		cmd.Stderr = os.Stderr
		if err := cmd.Run(); err != nil {
			fmt.Fprintf(os.Stderr, "Failed to install %s: %v\n", dep, err)
			os.Exit(1)
		}
	}

	fmt.Println("Dependencies installed successfully")
}